package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"log"

	"github.com/fernet/fernet-go"
)

// encrypt encrypts the given data using the provided Fernet key.
// The key must be a base64-encoded 32-byte string (as generated by generateKey).
func encrypt(data []byte, key string) ([]byte, error) {
	// Decode the base64-encoded key into raw 32-byte key
	rawKey, err := base64.URLEncoding.DecodeString(key)
	if err != nil {
		return nil, fmt.Errorf("failed to decode key: %w", err)
	}
	if len(rawKey) != 32 {
		return nil, fmt.Errorf("invalid key length: expected 32 bytes, got %d", len(rawKey))
	}

	// Create a Fernet instance with the raw key
	fernet := fernet.NewFernet(rawKey)

	// Encrypt the data
	token := fernet.Encrypt(data)

	// Encode the encrypted token as a string
	encrypted := token.Encode()

	// Return the encrypted data as a byte slice (equivalent to Python's bytes)
	return []byte(encrypted), nil
}

// decrypt decrypts the given encrypted data using the provided Fernet key.
// The key must be a base64-encoded 32-byte string (as generated by generateKey).
func decrypt(data []byte, key string) ([]byte, error) {
	// Decode the base64-encoded key into raw 32-byte key
	rawKey, err := base64.URLEncoding.DecodeString(key)
	if err != nil {
		return nil, fmt.Errorf("failed to decode key: %w", err)
	}
	if len(rawKey) != 32 {
		return nil, fmt.Errorf("invalid key length: expected 32 bytes, got %d", len(rawKey))
	}

	// Create a Fernet instance with the raw key
	fernet := fernet.NewFernet(rawKey)

	// Convert encrypted data from byte slice to string
	encryptedStr := string(data)

	// Decode and verify the token
	token, err := fernet.DecodeAndVerify(encryptedStr, 0)
	if err != nil {
		return nil, fmt.Errorf("failed to decode and verify token: %w", err)
	}

	// Decrypt the token
	decrypted := token.Decrypt()

	return decrypted, nil
}

// generateKey generates a new Fernet-compatible key.
// The key is returned as a base64-encoded string (equivalent to Python's Fernet.generate_key()).
func generateKey() (string, error) {
	key := make([]byte, 32)
	if _, err := rand.Read(key); err != nil {
		return "", fmt.Errorf("failed to generate random key: %w", err)
	}
	return base64.URLEncoding.EncodeToString(key), nil
}

// main is the entry point of the program.
// It generates a key, encrypts a sample string, and optionally decrypts it.
func main() {
	// Generate a new Fernet key
	key, err := generateKey()
	if err != nil {
		log.Fatalf("Failed to generate key: %v", err)
	}

	// Define the data to encrypt
	data := []byte("/safedir/test.txt")

	// Encrypt the data
	encrypted, err := encrypt(data, key)
	if err != nil {
		log.Fatalf("Encryption failed: %v", err)
	}
	fmt.Printf("Encrypted: %s\n", encrypted)

	// Decrypt the data (optional, for demonstration)
	decrypted, err := decrypt(encrypted, key)
	if err != nil {
		log.Fatalf("Decryption failed: %v", err)
	}
	fmt.Printf("Decrypted: %s\n", decrypted)
}